3816 /// Reorders the given \p Reuses mask according to the given \p Mask. \p Reuses
3817 /// contains original mask for the scalars reused in the node. Procedure
3818 /// transform this mask in accordance with the given \p Mask.
3819 static void reorderReuses(SmallVectorImpl<int> &Reuses, ArrayRef<int> Mask) {
3820   assert(!Mask.empty() && Reuses.size() == Mask.size() &&
3821          "Expected non-empty mask.");
3822   SmallVector<int> Prev(Reuses.begin(), Reuses.end());
3823   Prev.swap(Reuses);
3824   for (unsigned I = 0, E = Prev.size(); I < E; ++I)
3825     if (Mask[I] != PoisonMaskElem)
