14739 bool SLPVectorizerPass::vectorizeStores(ArrayRef<StoreInst *> Stores,
14740                                         BoUpSLP &R) {
14741   // We may run into multiple chains that merge into a single chain. We mark the
14742   // stores that we vectorized so that we don't visit the same store twice.
