14747   // already tried to be vectorized. Allows to skip the store ranges that were
14748   // already tried to be vectorized but the attempts were unsuccessful.
14749   DenseSet<std::pair<Value *, Value *>> TriedSequences;
14750   struct StoreDistCompare {
14751     bool operator()(const std::pair<unsigned, int> &Op1,
14752                     const std::pair<unsigned, int> &Op2) const {
14753       return Op1.second < Op2.second;
14754     }
14755   };
14756   // A set of pairs (index of store in Stores array ref, Distance of the store
14757   // address relative to base store address in units).
14758   using StoreIndexToDistSet =
14759       std::set<std::pair<unsigned, int>, StoreDistCompare>;
14760   auto TryToVectorize = [&](const StoreIndexToDistSet &Set) {
14761     int PrevDist = -1;
14762     BoUpSLP::ValueList Operands;
14763     // Collect the chain into a list.
14764     for (auto [Idx, Data] : enumerate(Set)) {
14765       if (Operands.empty() || Data.second - PrevDist == 1) {
14766         Operands.push_back(Stores[Data.first]);
14767         PrevDist = Data.second;
14768         if (Idx != Set.size() - 1)
14769           continue;
14770       }
14771       auto E = make_scope_exit([&, &DataVar = Data]() {
14772         Operands.clear();
14773         Operands.push_back(Stores[DataVar.first]);
14774         PrevDist = DataVar.second;
14775       });
14776 
14777       if (Operands.size() <= 1)
14778         continue;
14779 
14780       unsigned MaxVecRegSize = R.getMaxVecRegSize();
14781       unsigned EltSize = R.getVectorElementSize(Operands[0]);
14782       unsigned MaxElts = llvm::bit_floor(MaxVecRegSize / EltSize);
14783 
14784       unsigned MaxVF =
14785           std::min(R.getMaximumVF(EltSize, Instruction::Store), MaxElts);
14786       auto *Store = cast<StoreInst>(Operands[0]);
14787       Type *StoreTy = Store->getValueOperand()->getType();
14788       Type *ValueTy = StoreTy;
14789       if (auto *Trunc = dyn_cast<TruncInst>(Store->getValueOperand()))
14790         ValueTy = Trunc->getSrcTy();
14791       unsigned MinVF = TTI->getStoreMinimumVF(
14792           R.getMinVF(DL->getTypeSizeInBits(ValueTy)), StoreTy, ValueTy);
